text:
{
  "formal_minutes": {
    "meeting_meta": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": [
        "Minjun",
        "Seoyeon",
        "Doyun",
        "Hara"
      ]
    },
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트 통과를 전제로 금요일 15:00 KST를 공개 릴리스 목표 시점으로 둔다.",
        "certainty": "confirmed"
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인한다. 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다.",
        "certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "topic": "smoke-theme-pack.mjs 처리 방식",
        "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경하자.",
        "outcome": "rejected",
        "reason": "논의 후 채택되지 않았으며, 우선 package config를 점검하기로 결정됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "topic": "수요일 릴리스 제안",
        "detail": "수요일 릴리스는 내부 스트레치 골일 뿐 확정 일정이 아니다.",
        "certainty": "confirmed_as_non_final"
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 단계 검토",
        "detail": "목요일까지 가능하면 검토하자는 의견은 있었으나 담당자는 지정되지 않았다."
      },
      {
        "topic": "릴리스 노트에 수요일 스트레치 골 언급 여부",
        "detail": "답이 결정되지 않았다."
      },
      {
        "topic": "최종 릴리스 승인 권한자",
        "detail": "확정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로가 릴리스를 지연시킬 수 있다.",
        "certainty": "confirmed"
      },
      {
        "risk": "README 설치 단계가 오래되었으면 릴리스 노트가 사용자에게 오해를 줄 수 있다.",
        "certainty": "confirmed"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 골을 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "open",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "open",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로를 점검한다.",
      "due": "not specified",
      "status": "blocked_pending_smoke_result",
      "source_certainty": "confirmed"
    },
    {
      "owner": "unassigned",
      "task": "README 설치 단계를 가능하면 목요일까지 검토한다.",
      "due": "목요일 if possible",
      "status": "open",
      "source_certainty": "partially_confirmed_unassigned"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 스모크 테스트 결과 통과 여부를 확인한다.",
      "스모크 결과 이후 Hara의 tarball 경로 점검 결과를 확인한다.",
      "Doyun의 실패 트리아지 노트 작성 완료 여부를 확인한다.",
      "README 설치 단계 검토의 담당자 지정 필요 여부를 확인한다.",
      "최종 릴리스 승인 권한자를 확인한다.",
      "릴리스 노트에 내부 수요일 스트레치 골을 언급할지 결정이 필요한지 확인한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구",
      "지정되지 않은 담당자",
      "명시되지 않은 마감",
      "확정되지 않은 승인 권한자"
    ]
  },
  "non_invention_rules": [
    "인라인 합성 픽스처에 없는 고객, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "확정 결정과 제안, 스트레치 골, 미결 사항을 혼합하지 않는다.",
    "담당자가 지정되지 않은 항목에 임의 소유자를 부여하지 않는다.",
    "명시되지 않은 마감을 임의로 확정하지 않는다.",
    "수요일 일정은 확정 릴리스가 아니라 내부 스트레치 골로만 기록한다.",
    "거절된 제안은 최종 결정과 분리해 기록한다."
  ]
}
